import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App'
import ThemeProvider from './providers/ThemeProvider'
const container = document.getElementById('root')
const root = ReactDOM.createRoot(container)

root.render(
  <React.StrictMode>
    <ThemeProvider>
      <App />
    </ThemeProvider>
  </React.StrictMode>
);